import React from 'react';

const Experience = ({ data }) => {
  return (
    <section id="pengalaman" className="wadah-seksi">
      <h2>Pengalaman Profesional</h2>
      <div className="garis-waktu" role="list">
        {data.map((exp, index) => (
          <article key={index} className="item-waktu" role="listitem">
            <time className="tanggal-waktu">{exp.period}</time>
            <header className="kepala-waktu">
              <img src={exp.logo} alt={`Logo ${exp.company}`} className="logo-instansi" loading="lazy" />
              <div>
                <h3 className="judul-waktu" style={{ marginBottom: '0' }}>{exp.role}</h3>
                <h4 className="subjudul-waktu" style={{ marginBottom: '0', fontSize: '1rem' }}>{exp.company}</h4>
              </div>
            </header>
            <div className="deskripsi-waktu">
              <ul>
                {exp.description.map((point, idx) => (
                  <li key={idx}>{point}</li>
                ))}
              </ul>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default Experience;
